-- calc_customers_status_display_name
-- Field: Customers.StatusDisplayName
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: DisplayName from related Statuses

CREATE OR REPLACE FUNCTION calc_customers_status_display_name(p_customer_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT display_name::text FROM statuses WHERE statuse_id = (SELECT status FROM customers WHERE customer_id = p_customer_id));
$$ LANGUAGE sql STABLE;

