-- calc_customers_name
-- Field: Customers.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_customers_name(p_customer_id TEXT)
RETURNS TEXT AS $$
  SELECT (REPLACE(LOWER(calc_customers_full_name(p_customer_id)), ' ', '-'))::text;
$$ LANGUAGE sql STABLE;

-- calc_customers_full_name
-- Field: Customers.FullName
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_customers_full_name(p_customer_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(first_name, '') FROM customers WHERE customer_id = p_customer_id), ' ', (SELECT NULLIF(last_name, '') FROM customers WHERE customer_id = p_customer_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_customers_is_stopped
-- Field: Customers.IsStopped
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_customers_is_stopped(p_customer_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (calc_customers_status_is_blocking(p_customer_id) AND (SELECT NULLIF(first_name, '') FROM customers WHERE customer_id = p_customer_id) = 'Bob') THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

