-- calc_app_users_name
-- Field: AppUsers.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_app_users_name(p_app_user_id TEXT)
RETURNS TEXT AS $$
  SELECT (LOWER(REPLACE(REPLACE((SELECT NULLIF(email_address, '') FROM app_users WHERE app_user_id = p_app_user_id), '. ', '-'), '@', '-')))::text;
$$ LANGUAGE sql STABLE;

